package service

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"strings"
	"time"

	"github.com/dsjkeeplearning/kos-auth-backend/go-nebula-sidecar/config"
	"github.com/dsjkeeplearning/kos-auth-backend/go-nebula-sidecar/db"
	"github.com/rs/zerolog/log"
	"go.opentelemetry.io/contrib/instrumentation/net/http/otelhttp"
)

type TokenValidationResult struct {
	UserID string   `json:"userId"`
	Roles  []string `json:"roles"`
	Valid  bool     `json:"valid"`
}

type TokenService struct {
	cfg        *config.Config
	repo       *db.Repository
	httpClient *http.Client
}

func NewTokenService(cfg *config.Config, repo *db.Repository) *TokenService {
	return &TokenService{
		cfg:  cfg,
		repo: repo,
		httpClient: &http.Client{
			Timeout:   5 * time.Second,
			Transport: otelhttp.NewTransport(http.DefaultTransport),
		},
	}
}

// ValidateToken validates a JWT token, checking cache first, then the auth backend.
func (s *TokenService) ValidateToken(ctx context.Context, token string) (*TokenValidationResult, error) {
	if !isValidTokenFormat(token) {
		return &TokenValidationResult{Valid: false}, nil
	}

	tokenHash := hashToken(token)

	// Check cache first
	cached, err := s.repo.GetCachedToken(ctx, tokenHash)
	if err != nil {
		log.Warn().Err(err).Msg("failed to check token cache, falling through to backend")
	}
	if cached != nil {
		return &TokenValidationResult{
			UserID: cached.UserID,
			Roles:  cached.Roles,
			Valid:  true,
		}, nil
	}

	// Call auth backend
	result, err := s.callAuthBackend(ctx, token)
	if err != nil {
		log.Error().Err(err).Msg("auth backend validation failed")

		// Graceful fallback: check cache with extended TTL (1 min)
		cached, cacheErr := s.repo.GetCachedToken(ctx, tokenHash)
		if cacheErr == nil && cached != nil {
			log.Warn().Msg("using stale cache entry as fallback")
			return &TokenValidationResult{
				UserID: cached.UserID,
				Roles:  cached.Roles,
				Valid:  true,
			}, nil
		}

		return nil, fmt.Errorf("validate token: %w", err)
	}

	if !result.Valid {
		return result, nil
	}

	// Cache the result
	cacheEntry := &db.CachedToken{
		TokenHash: tokenHash,
		UserID:    result.UserID,
		Roles:     result.Roles,
		ExpiresAt: time.Now().Add(time.Duration(s.cfg.TokenCacheTTL) * time.Second),
	}
	if err := s.repo.CacheToken(ctx, cacheEntry); err != nil {
		log.Warn().Err(err).Msg("failed to cache token validation result")
	}

	return result, nil
}

func (s *TokenService) callAuthBackend(ctx context.Context, token string) (*TokenValidationResult, error) {
	url := fmt.Sprintf("%s%s", s.cfg.AuthBackendURL, s.cfg.AuthBackendTokenValidateURL)

	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, fmt.Errorf("create request: %w", err)
	}
	req.Header.Set("Authorization", "Bearer "+token)

	resp, err := s.httpClient.Do(req)
	if err != nil {
		return nil, fmt.Errorf("call auth backend: %w", err)
	}
	defer resp.Body.Close()

	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("read response: %w", err)
	}

	if resp.StatusCode == http.StatusUnauthorized || resp.StatusCode == http.StatusForbidden {
		return &TokenValidationResult{Valid: false}, nil
	}

	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("auth backend returned status %d", resp.StatusCode)
	}

	var result TokenValidationResult
	if err := json.Unmarshal(body, &result); err != nil {
		return nil, fmt.Errorf("parse response: %w", err)
	}
	result.Valid = true

	return &result, nil
}

// hashToken returns a SHA-256 hex digest of the token.
func hashToken(token string) string {
	h := sha256.Sum256([]byte(token))
	return hex.EncodeToString(h[:])
}

// isValidTokenFormat checks basic JWT format (3 dot-separated parts).
func isValidTokenFormat(token string) bool {
	token = strings.TrimSpace(token)
	if token == "" {
		return false
	}
	parts := strings.Split(token, ".")
	return len(parts) == 3
}

package service

import (
	"context"
	"crypto/sha256"
	"encoding/binary"
	"fmt"

	"github.com/dsjkeeplearning/kos-auth-backend/go-nebula-sidecar/db"
)

type AllocationService struct {
	repo *db.Repository
}

func NewAllocationService(repo *db.Repository) *AllocationService {
	return &AllocationService{repo: repo}
}

// AllocateIP determines the next available IP for a given node type.
// EC2: 192.168.100.10-99 (sequential per environment)
// Laptop: 192.168.100.100-199 (hash-based on user ID, with collision fallback)
func (s *AllocationService) AllocateIP(ctx context.Context, userID, nodeType, environment string) (string, error) {
	switch nodeType {
	case "ec2":
		return s.repo.GetNextAvailableIP(ctx, "ec2", environment)
	case "laptop":
		return s.allocateLaptopIP(ctx, userID)
	default:
		return "", fmt.Errorf("unknown node type: %s", nodeType)
	}
}

// allocateLaptopIP uses a hash of the user ID to pick a preferred IP,
// then falls back to sequential scan on collision.
func (s *AllocationService) allocateLaptopIP(ctx context.Context, userID string) (string, error) {
	preferred := hashUserToOctet(userID)
	ip := fmt.Sprintf("192.168.100.%d", preferred)

	exists, err := s.repo.CheckIPExists(ctx, ip)
	if err != nil {
		return "", fmt.Errorf("check IP: %w", err)
	}
	if !exists {
		return ip, nil
	}

	// Collision — fall back to sequential scan
	return s.repo.GetNextAvailableIP(ctx, "laptop", "")
}

// hashUserToOctet returns a value in [100, 199] based on user ID hash.
func hashUserToOctet(userID string) int {
	h := sha256.Sum256([]byte(userID))
	n := binary.BigEndian.Uint32(h[:4])
	return 100 + int(n%100)
}

package api

import (
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/dsjkeeplearning/kos-auth-backend/go-nebula-sidecar/service"
	"github.com/gin-gonic/gin"
	"github.com/rs/zerolog/log"
)

// rateLimitEntry tracks per-user request counts for rate limiting.
type rateLimitEntry struct {
	count     int
	windowEnd time.Time
}

// AuthMiddleware validates JWT tokens via the token service and injects user context.
func AuthMiddleware(tokenService *service.TokenService) gin.HandlerFunc {
	var mu sync.Mutex
	limits := make(map[string]*rateLimitEntry)

	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			respondError(c, http.StatusUnauthorized, "missing authorization header")
			c.Abort()
			return
		}

		token := strings.TrimPrefix(authHeader, "Bearer ")
		if token == authHeader {
			respondError(c, http.StatusUnauthorized, "invalid authorization format")
			c.Abort()
			return
		}

		result, err := tokenService.ValidateToken(c.Request.Context(), token)
		if err != nil {
			log.Error().Err(err).Msg("token validation error")
			respondError(c, http.StatusInternalServerError, "token validation failed")
			c.Abort()
			return
		}

		if !result.Valid {
			respondError(c, http.StatusUnauthorized, "invalid or expired token")
			c.Abort()
			return
		}

		// Rate limiting: 10 requests per hour per user
		mu.Lock()
		entry, exists := limits[result.UserID]
		now := time.Now()
		if !exists || now.After(entry.windowEnd) {
			entry = &rateLimitEntry{count: 0, windowEnd: now.Add(time.Hour)}
			limits[result.UserID] = entry
		}
		entry.count++
		currentCount := entry.count
		mu.Unlock()

		if currentCount > 10 {
			respondError(c, http.StatusTooManyRequests, "rate limit exceeded (10 requests per hour)")
			c.Abort()
			return
		}

		// Inject user info into context
		c.Set("userID", result.UserID)
		c.Set("roles", result.Roles)
		c.Next()
	}
}

// RequireRole checks that the authenticated user has one of the specified roles.
func RequireRole(roles ...string) gin.HandlerFunc {
	return func(c *gin.Context) {
		userRoles, exists := c.Get("roles")
		if !exists {
			respondError(c, http.StatusForbidden, "no roles found")
			c.Abort()
			return
		}

		roleList, ok := userRoles.([]string)
		if !ok {
			respondError(c, http.StatusForbidden, "invalid roles format")
			c.Abort()
			return
		}

		for _, required := range roles {
			for _, userRole := range roleList {
				if strings.EqualFold(required, userRole) {
					c.Next()
					return
				}
			}
		}

		respondError(c, http.StatusForbidden, "insufficient permissions")
		c.Abort()
	}
}

package api

import (
	"regexp"
)

// Request types

type GenerateCertRequest struct {
	NodeType   string `json:"nodeType" binding:"required"`
	NodeName   string `json:"nodeName" binding:"required"`
	DeviceInfo string `json:"deviceInfo"`
}

type GenerateEC2CertRequest struct {
	Environment  string `json:"environment" binding:"required"`
	InstanceName string `json:"instanceName" binding:"required"`
	UserID       string `json:"userId"`
}

type RevokeCertRequest struct {
	NodeName string `json:"nodeName" binding:"required"`
	Reason   string `json:"reason" binding:"required"`
}

// Response types

type GenerateCertResponse struct {
	Certificate   string            `json:"certificate"`
	PrivateKey    string            `json:"privateKey"`
	Config        string            `json:"config"`
	LighthouseIP  string            `json:"lighthouseIp"`
	LighthousePort int              `json:"lighthousePort"`
	StaticHostMap map[string][]string `json:"staticHostMap"`
	IP            string            `json:"ip"`
	ExpiresAt     string            `json:"expiresAt"`
}

type CertListResponse struct {
	Certificates []CertSummary `json:"certificates"`
}

type CertSummary struct {
	NodeName  string  `json:"nodeName"`
	NodeType  string  `json:"nodeType"`
	IP        string  `json:"ip"`
	CreatedAt string  `json:"createdAt"`
	ExpiresAt string  `json:"expiresAt"`
	IsRevoked bool    `json:"isRevoked"`
}

type RevokeCertResponse struct {
	Success   bool   `json:"success"`
	RevokedAt string `json:"revokedAt"`
}

// Validation

var validNodeName = regexp.MustCompile(`^[a-zA-Z0-9][a-zA-Z0-9._-]*$`)

func isValidNodeName(name string) bool {
	return len(name) >= 1 && len(name) <= 255 && validNodeName.MatchString(name)
}

func isValidNodeType(t string) bool {
	return t == "laptop" || t == "ec2"
}

func isValidEnvironment(env string) bool {
	return env == "uat" || env == "prod" || env == "staging" || env == "dev"
}

package api

import (
	"github.com/gin-gonic/gin"
)

type ErrorResponse struct {
	Error     string `json:"error"`
	RequestID string `json:"requestId,omitempty"`
}

type HealthResponse struct {
	Status      string `json:"status"`
	Database    string `json:"database"`
	AuthBackend string `json:"authBackend"`
}

func respondError(c *gin.Context, status int, message string) {
	requestID, _ := c.Get("requestID")
	rid, _ := requestID.(string)
	c.JSON(status, ErrorResponse{
		Error:     message,
		RequestID: rid,
	})
}

