package db_test

import (
	"context"
	"encoding/json"
	"testing"
	"time"

	"github.com/dsjkeeplearning/kos-auth-backend/go-nebula-sidecar/config"
	"github.com/dsjkeeplearning/kos-auth-backend/go-nebula-sidecar/db"
	"github.com/testcontainers/testcontainers-go/modules/postgres"
)

func setupTestDB(t *testing.T) (*db.Repository, func()) {
	t.Helper()
	ctx := context.Background()

	container, err := postgres.Run(ctx,
		"postgres:16-alpine",
		postgres.WithDatabase("testdb"),
		postgres.WithUsername("postgres"),
		postgres.WithPassword("postgres"),
		postgres.BasicWaitStrategies(),
	)
	if err != nil {
		t.Fatalf("start postgres container: %v", err)
	}

	connStr, err := container.ConnectionString(ctx, "sslmode=disable")
	if err != nil {
		container.Terminate(ctx)
		t.Fatalf("get connection string: %v", err)
	}

	cfg := &config.Config{
		DBHost:     "localhost",
		DBPort:     "5432",
		DBName:     "testdb",
		DBUser:     "postgres",
		DBPassword: "postgres",
		DBPoolSize: 2,
	}

	if err := db.RunMigrations(connStr); err != nil {
		container.Terminate(ctx)
		t.Fatalf("run migrations: %v", err)
	}

	pool, err := db.ConnectWithURL(ctx, connStr, cfg.DBPoolSize)
	if err != nil {
		container.Terminate(ctx)
		t.Fatalf("connect to db: %v", err)
	}

	repo := db.NewRepository(pool)
	cleanup := func() {
		pool.Close()
		container.Terminate(ctx)
	}
	return repo, cleanup
}

